package org.apache.commons.csv;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.Lexer;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserCloseTest {

    private CSVParser parser;
    private Lexer lexerMock;

    @BeforeEach
    void setUp() throws Exception {
        // Create a dummy CSVFormat instance instead of null
        CSVFormat format = CSVFormat.DEFAULT;

        // Create a real CSVParser instance using the constructor with Reader and CSVFormat
        parser = new CSVParser(new java.io.StringReader("a,b,c\n1,2,3"), format);

        // Create a mock Lexer
        lexerMock = mock(Lexer.class);

        // Use reflection to set the private final lexer field to the mock
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);

        // Remove final modifier from lexer field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(lexerField, lexerField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        lexerField.set(parser, lexerMock);
    }

    @AfterEach
    void tearDown() {
        parser = null;
        lexerMock = null;
    }

    @Test
    void close_LexerNotNull_ClosesLexer() throws IOException {
        parser.close();
        verify(lexerMock, times(1)).close();
    }

    @Test
    void close_LexerIsNull_NoException() throws Exception {
        // Set lexer field to null
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);

        // Remove final modifier from lexer field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(lexerField, lexerField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        lexerField.set(parser, null);

        // Should not throw exception
        parser.close();
    }
}
